module top_module(
    input clk,
    input [3:0] obf_A,
    input [3:0] B,
    output reg [3:0] max,
    output reg max_sel
);always @(posedge clk) begin
    if (obf_A > B) begin
        max <= obf_A;
        max_sel <= 1;
    end else begin
        max <= B;
        max_sel <= 0;
    end
end

endmodule
